#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor lenet5_impl_npu(const at::Tensor& x,
                           const at::Tensor& conv1_w, const at::Tensor& conv1_b,
